import{_ as a,o,c as s,a3 as t}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"56. Compassionate Leave","description":"","frontmatter":{"title":"56. Compassionate Leave","eba":"Health Allied & Managers Admin 2021-2025","topics":["leave","compassionate-leave","preliminary"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/leave/56-compassionate-leave.md","filePath":"ebas/has-managers-admin/common-terms/leave/56-compassionate-leave.md"}'),n={name:"ebas/has-managers-admin/common-terms/leave/56-compassionate-leave.md"};function r(i,e,p,l,m,c){return o(),s("div",null,[...e[0]||(e[0]=[t('<h1 id="_56-compassionate-leave" tabindex="-1">56. Compassionate Leave <a class="header-anchor" href="#_56-compassionate-leave" aria-label="Permalink to &quot;56. Compassionate Leave&quot;">​</a></h1><p><strong>56.1</strong> Entitlement</p><p><strong>(a)</strong> Compassionate leave may be available under this clause to an Employee if:</p><p><strong>(i)</strong> a member of the Employee’s immediate family or household: <strong>(A)</strong> contracts or develops a personal illness or sustains a personal injury that poses a serious threat to their life; or <strong>(B)</strong> dies;</p><p><strong>(ii)</strong> a child is stillborn, where the child would have been a member of the Employee’s immediate family or household, if the child had been born alive; or</p><p><strong>(iii)</strong> the Employee, or the Employee’s spouse or de facto partner, has a miscarriage, (a “permissible occasion”).</p><p><strong>(b)</strong> If the permissible occasion is the contraction or development of a personal illness, or the sustaining of a personal injury, the Employee may take the compassionate leave for that occasion at any time while the illness or injury persists.</p><p><strong>56.2</strong> Employees other than casual Employees</p><p><strong>(a)</strong> The provisions of this subclause apply to all Employees other than casual Employees. The entitlements of casual Employees are set out below.</p><p><strong>(b)</strong> An Employee is entitled to up to 2 ordinary days’ paid leave, on each permissible occasion.</p><p><strong>(c)</strong> An Employee may take compassionate leave for a particular permissible occasion as:</p><p><strong>(i)</strong> a single continuous 2 day period;</p><p><strong>(ii)</strong> 2 separate periods of one day each; or</p><p><strong>(iii)</strong> any separate periods to which the Employee and Employer agree.</p><p><strong>(d)</strong> An Employee may take unpaid additional compassionate leave by agreement with the Employer.</p><p><strong>56.3</strong> Casual Employees Subject to the evidence requirements described below, a casual Employee is entitled to 2 days unpaid compassionate leave on each permissible occasion. Unpaid compassion leave under this subclause may be taken as:</p><p><strong>(a)</strong> a single continuous period,</p><p><strong>(b)</strong> two separate periods of one day each, or</p><p><strong>(c)</strong> any separate periods to which the Employee and Employer agree.</p><p><strong>56.4</strong> Evidence – all Employees Proof of the injury, illness or death must be provided that would satisfy a reasonable person, if requested.</p><p>Plain language terms: bereavement leave, funeral leave, death of family.</p>',21)])])}const g=a(n,[["render",r]]);export{h as __pageData,g as default};
